const helpers = this.helpers;
const WMO = { 0:'Ceu limpo',1:'Predom. limpo',2:'Parc. nublado',3:'Nublado',45:'Nevoa',48:'Nevoa c/ geada',51:'Garoa fraca',53:'Garoa',55:'Garoa forte',61:'Chuva fraca',63:'Chuva',65:'Chuva forte',66:'Chuva congelante',67:'Chuva congelante forte',71:'Neve fraca',73:'Neve',75:'Neve forte',77:'Graos de neve',80:'Aguaceiros fracos',81:'Aguaceiros',82:'Aguaceiros fortes',85:'Aguaceiros de neve',86:'Aguaceiros de neve fortes',95:'Trovoada',96:'Trovoada c/ granizo',99:'Trovoada forte c/ granizo' };

function buildChecklist(f){
  const out = [];
  const { temp_max:tmax, temp_min:tmin, precip_prob:prob, precip_mm:mm, uv_index:uv, weather_code:code } = f;
  if (tmin != null && tmin < 5) out.push('casaco pesado + touca e luvas');
  else if (tmin != null && tmin < 10) out.push('casaco quente / blusa de frio');
  else if (tmin != null && tmin < 15) out.push('casaco leve para a noite');
  if (tmax != null && tmax >= 30) out.push('roupas leves e respiraveis','bone ou chapeu','garrafa de agua (hidratacao)');
  else if (tmax != null && tmax >= 25) out.push('roupas leves');
  if ((prob != null && prob >= 50) || (mm != null && mm >= 1)) out.push('guarda-chuva ou capa de chuva');
  else if (prob != null && prob >= 30) out.push('guarda-chuva dobravel (pode chover)');
  if (uv != null && uv >= 6) out.push('protetor solar FPS alto','oculos de sol');
  else if (uv != null && uv >= 3) out.push('protetor solar');
  if ([71,73,75,77,85,86].includes(code)) out.push('roupa de neve / calcado impermeavel');
  if ([95,96,99].includes(code)) out.push('capa de chuva (risco de trovoada)');
  if (out.length === 0) out.push('roupas confortaveis para clima ameno');
  return out;
}

async function geocode(city){
  try {
    const url = 'https://geocoding-api.open-meteo.com/v1/search?name=' + encodeURIComponent(city) + '&count=1&language=pt&format=json';
    const data = await helpers.httpRequest({ url, json: true });
    const r = (data.results || [])[0];
    return r ? { lat: r.latitude, lon: r.longitude, resolved: r.name + (r.country ? ', ' + r.country : '') } : null;
  } catch (e){ return null; }
}

const items = $input.all();
const root = (items[0] && items[0].json && (items[0].json.body || items[0].json)) || {};
const itinerary = Array.isArray(root.itinerary) ? root.itinerary : [];

const itinerary_weather = [];
const checklists = [];

for (const stop of itinerary){
  const city = stop.city || stop.name || stop.destino || '';
  const date = stop.date || stop.data || null;
  let lat = stop.lat != null ? Number(stop.lat) : null;
  let lon = stop.lon != null ? Number(stop.lon) : (stop.lng != null ? Number(stop.lng) : null);
  let resolved = city;

  if ((lat == null || lon == null) && city){
    const g = await geocode(city);
    if (g){ lat = g.lat; lon = g.lon; resolved = g.resolved; }
  }
  if (lat == null || lon == null){
    itinerary_weather.push({ city, date, error: 'sem coordenadas e geocoding falhou' });
    checklists.push({ city, date, items: ['nao foi possivel obter previsao; leve roupas versateis'] });
    continue;
  }

  const qs = new URLSearchParams({
    latitude: String(lat), longitude: String(lon),
    daily: 'temperature_2m_max,temperature_2m_min,precipitation_sum,precipitation_probability_max,weather_code,uv_index_max',
    timezone: 'auto'
  });
  if (date){ qs.set('start_date', date); qs.set('end_date', date); } else { qs.set('forecast_days','1'); }

  try {
    const data = await helpers.httpRequest({ url: 'https://api.open-meteo.com/v1/forecast?' + qs.toString(), json: true });
    const d = data.daily || {};
    const f = {
      temp_max: (d.temperature_2m_max||[])[0] ?? null,
      temp_min: (d.temperature_2m_min||[])[0] ?? null,
      precip_mm: (d.precipitation_sum||[])[0] ?? null,
      precip_prob: (d.precipitation_probability_max||[])[0] ?? null,
      uv_index: (d.uv_index_max||[])[0] ?? null,
      weather_code: (d.weather_code||[])[0] ?? null,
    };
    const fdate = (d.time||[])[0] ?? date;
    const weather = WMO[f.weather_code] || ('codigo ' + f.weather_code);
    itinerary_weather.push({
      city: resolved, date: fdate, lat, lon,
      temp_min_c: f.temp_min, temp_max_c: f.temp_max,
      precip_mm: f.precip_mm, precip_prob_pct: f.precip_prob,
      uv_index_max: f.uv_index, weather_code: f.weather_code, weather,
      source: 'open-meteo', confidence: date ? 'forecast' : 'hoje'
    });
    checklists.push({ city: resolved, date: fdate, items: buildChecklist(f) });
  } catch (e){
    itinerary_weather.push({ city: resolved, date, error: 'open-meteo falhou: ' + e.message });
    checklists.push({ city: resolved, date, items: ['previsao indisponivel; leve roupas versateis'] });
  }
}

return [{ json: { ok: true, generated_with: 'n8n + open-meteo', itinerary_weather, checklists } }];
